svg.script:
(function () {
  const svg = document.documentElement;

  // --- GitHub-like grid setup
  const cols = 53;
  const rows = 7;
  const cell = 11;
  const gap = 4;
  const gridX = 32;
  const gridY = 10;

  const palette = ["#161b22", "#0e4429", "#006d32", "#26a641", "#39d353"];

  const grid = svg.getElementById("grid");
  const months = svg.getElementById("months");
  const days = svg.getElementById("days");
  const scoreText = svg.getElementById("scoreText");

  function cellPos(c, r) {
    return {
      x: 48 + gridX + c * (cell + gap),
      y: 92 + gridY + r * (cell + gap)
    };
  }

  // month labels close to GitHub layout
  const monthNames = [
    ["May", 0], ["Jun", 4], ["Jul", 8], ["Aug", 13], ["Sep", 17], ["Oct", 21],
    ["Nov", 26], ["Dec", 30], ["Jan", 35], ["Feb", 39], ["Mar", 43], ["Apr", 48]
  ];
  monthNames.forEach(([name, c]) => {
    const t = document.createElementNS("http://www.w3.org/2000/svg", "text");
    t.setAttribute("class", "month");
    t.setAttribute("x", gridX + c * (cell + gap));
    t.setAttribute("y", -2);
    t.textContent = name;
    months.appendChild(t);
  });

  [["Mon",1],["Wed",3],["Fri",5]].forEach(([name, r]) => {
    const t = document.createElementNS("http://www.w3.org/2000/svg", "text");
    t.setAttribute("class", "day");
    t.setAttribute("x", 0);
    t.setAttribute("y", gridY + r * (cell + gap) + 9);
    t.textContent = name;
    days.appendChild(t);
  });

  // seeded pseudo-random so it always looks the same
  let seed = 1337;
  function rand() {
    seed = (seed * 1664525 + 1013904223) % 4294967296;
    return seed / 4294967296;
  }

  // Create a believable GitHub-like heatmap
  const cells = [];
  for (let c = 0; c < cols; c++) {
    for (let r = 0; r < rows; r++) {
      const p = rand();

      // gentle clusters so it feels like a real contribution graph
      const seasonalBoost =
        (c > 4 && c < 11 ? 0.06 : 0) +
        (c > 15 && c < 22 ? 0.10 : 0) +
        (c > 33 && c < 39 ? 0.07 : 0) +
        (c > 43 && c < 50 ? 0.10 : 0);

      const rowBias = (r === 0 || r === 6) ? -0.05 : 0;
      const v = p + seasonalBoost + rowBias;

      let level = 0;
      if (v > 0.83) level = 4;
      else if (v > 0.64) level = 3;
      else if (v > 0.42) level = 2;
      else if (v > 0.22) level = 1;

      const pos = cellPos(c, r);
      const rect = document.createElementNS("http://www.w3.org/2000/svg", "rect");
      rect.setAttribute("class", "cell");
      rect.setAttribute("x", pos.x);
      rect.setAttribute("y", pos.y);
      rect.setAttribute("width", cell);
      rect.setAttribute("height", cell);
      rect.setAttribute("rx", 2);
      rect.setAttribute("fill", palette[level]);
      rect.dataset.col = c;
      rect.dataset.row = r;
      rect.dataset.level = level;
      grid.appendChild(rect);
      cells.push(rect);
    }
  }

  function getCell(c, r) {
    return cells.find(el => +el.dataset.col === c && +el.dataset.row === r);
  }

  // --- Targets that the ball will actually destroy
  const targets = [
    [47, 5],
    [42, 4],
    [37, 3],
    [31, 2],
    [26, 1],
    [20, 2],
    [15, 3],
    [11, 4],
    [8, 5]
  ];

  // make targets visible/high-value like real active days
  targets.forEach(([c, r]) => {
    const rect = getCell(c, r);
    if (rect) rect.setAttribute("fill", palette[4]);
  });

  // --- Animation timeline
  const duration = 7.2; // seconds
  const start = performance.now();

  const ball = svg.getElementById("ball");
  const paddle = svg.getElementById("paddle");
  const trail = svg.getElementById("ballTrail");

  const paddleY = 370;
  const paddleW = 92;
  const paddleH = 10;

  // helper: center of a cell
  function centerOfCell(c, r) {
    const p = cellPos(c, r);
    return { x: p.x + cell / 2, y: p.y + cell / 2 };
  }

  // Ball route:
  // starts near paddle, bounces through selected cells, returns to paddle, repeats
  const pts = [];
  const startX = 790;
  const startY = paddleY - 12;

  pts.push({ x: startX, y: startY });
  targets.forEach(([c, r]) => pts.push(centerOfCell(c, r)));
  pts.push({ x: 240, y: 300 });       // lower bounce
  pts.push({ x: 510, y: paddleY - 12 }); // paddle intercept
  pts.push({ x: startX, y: startY }); // close loop

  function lerp(a, b, t) {
    return a + (b - a) * t;
  }

  function segmentLengths(points) {
    const lengths = [];
    let total = 0;
    for (let i = 0; i < points.length - 1; i++) {
      const dx = points[i + 1].x - points[i].x;
      const dy = points[i + 1].y - points[i].y;
      const len = Math.hypot(dx, dy);
      lengths.push(len);
      total += len;
    }
    return { lengths, total };
  }

  const seg = segmentLengths(pts);
  const cumulative = [0];
  for (let i = 0; i < seg.lengths.length; i++) {
    cumulative.push(cumulative[i] + seg.lengths[i] / seg.total);
  }

  function pointAt(t) {
    t = t % 1;
    let i = 0;
    while (i < cumulative.length - 1 && t > cumulative[i + 1]) i++;
    const localT = (t - cumulative[i]) / (cumulative[i + 1] - cumulative[i]);
    return {
      x: lerp(pts[i].x, pts[i + 1].x, localT),
      y: lerp(pts[i].y, pts[i + 1].y, localT)
    };
  }

  // build trail from points
  trail.setAttribute("d", "M " + pts.map(p => `${p.x} ${p.y}`).join(" L "));

  // target hit windows
  const hitMoments = targets.map((_, i) => cumulative[i + 1]);

  const destroyed = new Set();
  let score = 0;

  function updatePaddle(ballX) {
    // Track the ball during the final descent near the paddle
    // and stay plausible during the rest of the loop.
    let x = ballX - paddleW / 2;

    const minX = 48;
    const maxX = 932 - paddleW;
    x = Math.max(minX, Math.min(maxX, x));

    paddle.setAttribute("x", x);
    paddle.setAttribute("y", paddleY);
  }

  function resetTargets() {
    destroyed.clear();
    score = 0;
    scoreText.textContent = String(score).padStart(4, "0");
    targets.forEach(([c, r]) => {
      const rect = getCell(c, r);
      if (!rect) return;
      rect.style.opacity = "1";
      rect.style.transform = "";
      rect.setAttribute("fill", palette[4]);
    });
  }

  let lastLoop = -1;
  function frame(now) {
    const elapsed = (now - start) / 1000;
    const loop = Math.floor(elapsed / duration);
    const t = (elapsed % duration) / duration;

    if (loop !== lastLoop) {
      resetTargets();
      lastLoop = loop;
    }

    const p = pointAt(t);
    ball.setAttribute("cx", p.x);
    ball.setAttribute("cy", p.y);

    // paddle and ball use the same timeline, so they stay aligned
    updatePaddle(p.x);

    // destroy cells exactly when their time is reached
    hitMoments.forEach((hm, i) => {
      if (t >= hm && !destroyed.has(i)) {
        destroyed.add(i);
        const [c, r] = targets[i];
        const rect = getCell(c, r);
        if (rect) {
          rect.style.opacity = "0";
          rect.style.transformOrigin = "center";
          rect.style.transformBox = "fill-box";
          rect.style.transform = "scale(0.15)";
        }
        score += 100;
        scoreText.textContent = String(score).padStart(4, "0");
      }
    });

    requestAnimationFrame(frame);
  }

  // initial paddle position
  paddle.setAttribute("x", startX - paddleW / 2);
  paddle.setAttribute("y", paddleY);

  requestAnimationFrame(frame);
})();
